# import packages and helper algorithmsimport torchimport torch.nn as nn # cross entropy lossimport torch.optim as optim # SGDimport numpy as npfrom copy import deepcopy # copy for RP vs IPfrom helpers.NetworkFunction import MotorLearningRNNfrom helpers.DataGenerator import generate_synthetic_datafrom helpers.TorchFunctions import train_evaluate_model, vulnerability_testfrom joblib import Parallel, delayed # for better CPU performance# set global learning rate (2%)lr = 0.02def run_model(seed): # 1/100 repetition    np.random.seed(seed)    torch.manual_seed(seed)    """    Handles the full pipeline:        - Data generation        - Pre train        - Deep copy        - Train RP version        - Train IP version        - Run all tests (5)        - Return all metrics    """        # set up all parameters    input_size = 7 # model structure    hidden_size = 7    output_size = 4    batch_size = 20    num_training_sequences = 3    num_pre_training_sequences = 10    num_test_sequences = 100 # 100 novel sequences        # create global learning rate & print    global lr    print('Learning Rate:', lr)        # --------------- Data Generation -----------------        """    # X_repetitive = input, 7 action motor sequences (with noise)        # Sequences ordered in blocked fashion: AAA BBB CCC    # y_repetitive = clean one-hot categorical target matching X_repetitive    # X_interleaved = 7 action motor sequences with noise, but in random order: ABC BCA CAB    # y_interleaved = target one hot 'matrices' matching X_interleaved        # X_pre, y_pre = input and target of the 10 x 100 pretraining sequences    # X_test, y_test = the 100 novel motor sequences in the testing phase    """        X_repetitive, y_repetitive, X_interleaved, y_interleaved = generate_synthetic_data(num_training_sequences, samples_per_sequence=5000, add_input_noise=True)    print(X_repetitive.shape)    print(y_repetitive.shape)    # pretraining stage follows repatitive style only    X_pre, y_pre, _, _ = generate_synthetic_data(num_pre_training_sequences, samples_per_sequence=100, add_input_noise=True)        # for testing it does not matter if the sequences are repetitive or interleaved    _, _, X_test, y_test = generate_synthetic_data(num_test_sequences, add_input_noise=True)            # --------------- Model Construction -----------------        # Instantiate pretraining model    model1 = MotorLearningRNN(input_size, hidden_size, output_size, num_outputs=input_size)    # Loss: Cross entropy loss; Optimizer: SGD    criterion = nn.CrossEntropyLoss()    optimizer1 = optim.SGD(model1.parameters(), lr=lr, momentum=0.0) # pure vanilla SGD            # --------------- Pretraining Phase -----------------        total_num_epochs_pre = X_pre.shape[0] // batch_size    print(f"Total number of epochs for pre-training: {total_num_epochs_pre}")        # pretraining call, only generalization loss is retained    _, _, loss_test_pre, _, loss_test_array_pre = train_evaluate_model(X_pre, y_pre, X_pre, y_pre, X_test, y_test,                                                                       model1, criterion, optimizer1,                                                                       is_dislplay_loss=False)        # copy pretrained model for IP, same weights, control    model2 = deepcopy(model1)        # create new optimizers for the two copied models    optimizer1 = optim.SGD(model1.parameters(), lr=lr, momentum=0.0)    optimizer2 = optim.SGD(model2.parameters(), lr=lr, momentum=0.0)        # --------------- Repetitive Practice (RP) Training Phase -----------------        # train model1 under repetitively structured inputs    print("\nRepetitive Practice:")    loss_array_rp, loss_retention_rp, loss_test_rp, loss_retention_array_rp, loss_test_array_rp = train_evaluate_model(    X_repetitive, y_repetitive, X_repetitive, y_repetitive, X_test, y_test, model1, criterion, optimizer1, is_dislplay_loss=False)        # --------------- Interleaved Practice (IP) Training Phase -----------------    print("\nInterleaved Practice:")        # notice: retention evaluation sets are repetitive, not interleaved    loss_array_ip, loss_retention_ip, loss_test_ip, loss_retention_array_ip, loss_test_array_ip = train_evaluate_model(    X_interleaved, y_interleaved, X_repetitive, y_repetitive, X_test, y_test, model2, criterion, optimizer2, is_dislplay_loss=False)            # testing schemes A and B were done as part of the training and testing phase        # --------------- Vulnerability Testing Phase -----------------        print("\nVulnerability Test for Repetitive Practice:")    optimizer_rp = optim.SGD(model1.parameters(), lr=lr, momentum=0.0)    loss_retention_noisy_array_rp, loss_test_noisy_array_rp, loss_retention_pruned_array_rp, loss_test_pruned_array_rp, loss_retention_interf_array_rp, loss_test_interf_array_rp = vulnerability_test(    X_repetitive, y_repetitive, X_test, y_test, model1, criterion, optimizer_rp,    num_repeat_noisy=100, num_repeat_pruned=100, num_interference_steps=100)        print("\nVulnerability Test for Interleaved Practice:")    optimizer_ip = optim.SGD(model2.parameters(), lr=lr, momentum=0.0)    loss_retention_noisy_array_ip, loss_test_noisy_array_ip, loss_retention_pruned_array_ip, loss_test_pruned_array_ip, loss_retention_interf_array_ip, loss_test_interf_array_ip = vulnerability_test(        X_repetitive, y_repetitive, X_test, y_test, model2, criterion, optimizer_ip, num_repeat_noisy=100,         num_repeat_pruned=100, num_interference_steps=100)        return loss_test_pre, loss_array_rp, loss_retention_rp, loss_test_rp, loss_array_ip, loss_retention_ip, loss_test_ip, loss_retention_array_rp, loss_test_array_rp, loss_retention_array_ip, loss_test_array_ip, loss_test_array_pre, loss_retention_noisy_array_rp, loss_test_noisy_array_rp, loss_retention_noisy_array_ip, loss_test_noisy_array_ip, loss_retention_pruned_array_rp, loss_test_pruned_array_rp, loss_retention_pruned_array_ip, loss_test_pruned_array_ip, loss_retention_interf_array_rp, loss_test_interf_array_rp, loss_retention_interf_array_ip, loss_test_interf_array_ip# run 100 experiments in parallelresults = Parallel(n_jobs=-1)(delayed(run_model)(1000 - i) for i in range(100))# each results[i] is a 24-element tuple (run_model() returns 24 arrays per run)# we reorganize the data from [grouped by run] to [grouped by metric] for downstream analysis"""Blocked = rpInterleaved = ip"""loss_test_pre_list = [results[i][0] for i in range(len(results))]loss_array_blocked_list = [results[i][1] for i in range(len(results))]loss_retention_blocked_list = [results[i][2] for i in range(len(results))]loss_test_blocked_list = [results[i][3] for i in range(len(results))]loss_array_random_list = [results[i][4] for i in range(len(results))]loss_retention_random_list = [results[i][5] for i in range(len(results))]loss_test_random_list = [results[i][6] for i in range(len(results))]loss_retention_array_blocked_list = [results[i][7] for i in range(len(results))]loss_test_array_blocked_list = [results[i][8] for i in range(len(results))]loss_retention_array_random_list = [results[i][9] for i in range(len(results))]loss_test_array_random_list = [results[i][10] for i in range(len(results))]loss_test_array_pre_list = [results[i][11] for i in range(len(results))]loss_retention_noisy_array_blocked_list = [results[i][12] for i in range(len(results))]loss_test_noisy_array_blocked_list = [results[i][13] for i in range(len(results))]loss_retention_noisy_array_random_list = [results[i][14] for i in range(len(results))]loss_test_noisy_array_random_list = [results[i][15] for i in range(len(results))]loss_retention_pruned_array_blocked_list = [results[i][16] for i in range(len(results))]loss_test_pruned_array_blocked_list = [results[i][17] for i in range(len(results))]loss_retention_pruned_array_random_list = [results[i][18] for i in range(len(results))]loss_test_pruned_array_random_list = [results[i][19] for i in range(len(results))]loss_retention_interf_array_blocked_list = [results[i][20] for i in range(len(results))]loss_test_interf_array_blocked_list = [results[i][21] for i in range(len(results))]loss_retention_interf_array_random_list = [results[i][22] for i in range(len(results))]loss_test_interf_array_random_list = [results[i][23] for i in range(len(results))]# change list to numpy arrayloss_test_pre_array = np.array(loss_test_pre_list)loss_array_blocked_array = np.stack(loss_array_blocked_list, axis=0)loss_retention_blocked_array = np.array(loss_retention_blocked_list)loss_test_blocked_array = np.array(loss_test_blocked_list)loss_array_random_array = np.stack(loss_array_random_list, axis=0)loss_retention_random_array = np.array(loss_retention_random_list)loss_test_random_array = np.array(loss_test_random_list)loss_retention_array_blocked_array = np.stack(loss_retention_array_blocked_list, axis=0)loss_test_array_blocked_array = np.stack(loss_test_array_blocked_list, axis=0)loss_retention_array_random_array = np.stack(loss_retention_array_random_list, axis=0)loss_test_array_random_array = np.stack(loss_test_array_random_list, axis=0)loss_test_array_pre_array = np.stack(loss_test_array_pre_list, axis=0)loss_retention_noisy_array_blocked = np.stack(loss_retention_noisy_array_blocked_list, axis=0)loss_test_noisy_array_blocked = np.stack(loss_test_noisy_array_blocked_list, axis=0)loss_retention_noisy_array_random = np.stack(loss_retention_noisy_array_random_list, axis=0)loss_test_noisy_array_random = np.stack(loss_test_noisy_array_random_list, axis=0)loss_retention_pruned_array_blocked = np.stack(loss_retention_pruned_array_blocked_list, axis=0)loss_test_pruned_array_blocked = np.stack(loss_test_pruned_array_blocked_list, axis=0)loss_retention_pruned_array_random = np.stack(loss_retention_pruned_array_random_list, axis=0)loss_test_pruned_array_random = np.stack(loss_test_pruned_array_random_list, axis=0)loss_retention_interf_array_blocked = np.stack(loss_retention_interf_array_blocked_list, axis=0)loss_test_interf_array_blocked = np.stack(loss_test_interf_array_blocked_list, axis=0)loss_retention_interf_array_random = np.stack(loss_retention_interf_array_random_list, axis=0)loss_test_interf_array_random = np.stack(loss_test_interf_array_random_list, axis=0)# print size of loss_retension_array_blocked_array and loss_test_array_blocked_arrayprint(f'Size of loss_retention_array_blocked_array: {loss_retention_array_blocked_array.shape}')print(f'Size of loss_test_array_blocked_array: {loss_test_array_blocked_array.shape}')# create a folder name with the learning rate with replace . with _results_folder = f'results_lr_{str(lr).replace(".", "_")}'# create a folder to save the resultsimport osif not os.path.exists(results_folder):    os.makedirs(results_folder)# save the resultsnp.save(results_folder + '/loss_test_pre_array.npy', loss_test_pre_array)np.save(results_folder + '/loss_array_blocked_array.npy', loss_array_blocked_array)np.save(results_folder + '/loss_retention_blocked_array.npy', loss_retention_blocked_array)np.save(results_folder + '/loss_test_blocked_array.npy', loss_test_blocked_array)np.save(results_folder + '/loss_array_random_array.npy', loss_array_random_array)np.save(results_folder + '/loss_retention_random_array.npy', loss_retention_random_array)np.save(results_folder + '/loss_test_random_array.npy', loss_test_random_array)np.save(results_folder + '/loss_retention_array_blocked_array.npy', loss_retention_array_blocked_array)np.save(results_folder + '/loss_test_array_blocked_array.npy', loss_test_array_blocked_array)np.save(results_folder + '/loss_retention_array_random_array.npy', loss_retention_array_random_array)np.save(results_folder + '/loss_test_array_random_array.npy', loss_test_array_random_array)np.save(results_folder + '/loss_test_array_pre_array.npy', loss_test_array_pre_array)np.save(results_folder + '/loss_retention_noisy_array_blocked.npy', loss_retention_noisy_array_blocked)np.save(results_folder + '/loss_test_noisy_array_blocked.npy', loss_test_noisy_array_blocked)np.save(results_folder + '/loss_retention_noisy_array_random.npy', loss_retention_noisy_array_random)np.save(results_folder + '/loss_test_noisy_array_random.npy', loss_test_noisy_array_random)np.save(results_folder + '/loss_retention_pruned_array_blocked.npy', loss_retention_pruned_array_blocked)np.save(results_folder + '/loss_test_pruned_array_blocked.npy', loss_test_pruned_array_blocked)np.save(results_folder + '/loss_retention_pruned_array_random.npy', loss_retention_pruned_array_random)np.save(results_folder + '/loss_test_pruned_array_random.npy', loss_test_pruned_array_random)np.save(results_folder + '/loss_retention_interf_array_blocked.npy', loss_retention_interf_array_blocked)np.save(results_folder + '/loss_test_interf_array_blocked.npy', loss_test_interf_array_blocked)np.save(results_folder + '/loss_retention_interf_array_random.npy', loss_retention_interf_array_random)np.save(results_folder + '/loss_test_interf_array_random.npy', loss_test_interf_array_random)                                                                                                    